文件读取工具 - 支持 TXT, MD, DOCX, PDF 格式
自动保存到 JSONL 文件，支持增量导入和去重
"""

import os
import json
import time
from datetime import datetime
from pathlib import Path

try:
    from docx import Document
except ImportError:
    Document = None
    print("警告: python-docx 未安装，无法处理 DOCX 文件")

try:
    import fitz  # PyMuPDF
except ImportError:
    fitz = None
    print("警告: PyMuPDF 未安装，无法处理 PDF 文件")


class FileReader:
    """统一的文件读取工具类"""

    # 类变量，用于记录已处理的文件
    _processed_files = set()

    # 支持的文件类型
    SUPPORTED_EXTS = {
        '.txt': '文本文件',
        '.md': 'Markdown',
        '.markdown': 'Markdown',
        '.docx': 'Word文档',
        '.pdf': 'PDF文档'
    }

    @classmethod
    def read_txt(cls, file_path, encoding='utf-8'):
        """读取 TXT 文件"""
        try:
            with open(file_path, 'r', encoding=encoding) as f:
                return f.read()
        except UnicodeDecodeError:
            # 如果 UTF-8 失败，尝试 GBK 编码
            try:
                with open(file_path, 'r', encoding='gbk') as f:
                    return f.read()
            except Exception as e:
                print(f"读取 TXT 失败（GBK编码）: {e}")
                return None
        except Exception as e:
            print(f"读取 TXT 失败: {e}")
            return None

    @classmethod
    def read_md(cls, file_path, encoding='utf-8'):
        """读取 Markdown 文件"""
        return cls.read_txt(file_path, encoding)

    @classmethod
    def read_docx(cls, file_path):
        """读取 DOCX 文件 - 完整读取所有内容"""
        if Document is None:
            print("错误: python-docx 未安装，无法处理 DOCX 文件")
            return None

        try:
            doc = Document(file_path)
            text_parts = []

            # 1. 提取所有段落
            for para in doc.paragraphs:
                text_parts.append(para.text)

            # 2. 提取所有表格
            if doc.tables:
                text_parts.append("\n" + "="*50)
                text_parts.append("表格内容：")
                text_parts.append("="*50)

                for table_idx, table in enumerate(doc.tables, 1):
                    text_parts.append(f"\n表格 {table_idx}:")
                    for row_idx, row in enumerate(table.rows):
                        row_text = []
                        for cell in row.cells:
                            cell_text = cell.text.strip()
                            if cell_text:
                                row_text.append(cell_text)
                        if row_text:
                            text_parts.append(f"  第{row_idx+1}行: {' | '.join(row_text)}")
                    text_parts.append("")

            # 3. 提取页眉
            for section in doc.sections:
                if section.header:
                    header_text = []
                    for para in section.header.paragraphs:
                        if para.text.strip():
                            header_text.append(para.text)
                    if header_text:
                        text_parts.append(f"\n[页眉] {' '.join(header_text)}")

            # 4. 提取页脚
            for section in doc.sections:
                if section.footer:
                    footer_text = []
                    for para in section.footer.paragraphs:
                        if para.text.strip():
                            footer_text.append(para.text)
                    if footer_text:
                        text_parts.append(f"[页脚] {' '.join(footer_text)}")

            full_text = '\n'.join(text_parts)
            print(f"DOCX 提取完成，共 {len(full_text)} 字符")

            return full_text

        except Exception as e:
            print(f"读取 DOCX 失败: {e}")
            import traceback
            traceback.print_exc()
            return None

    @classmethod
    def read_pdf(cls, file_path):
        """读取 PDF 文件"""
        if fitz is None:
            print("错误: PyMuPDF 未安装，无法处理 PDF 文件")
            return None

        try:
            doc = fitz.open(file_path)
            text_parts = []

            for page_num, page in enumerate(doc, 1):
                page_text = page.get_text()
                if page_text.strip():
                    text_parts.append(f"=== 第 {page_num} 页 ===")
                    text_parts.append(page_text)
                    text_parts.append("")

            doc.close()
            full_text = '\n'.join(text_parts)
            print(f"PDF 提取完成，共 {len(full_text)} 字符，{len(doc)} 页")

            return full_text

        except Exception as e:
            print(f"读取 PDF 失败: {e}")
            import traceback
            traceback.print_exc()
            return None

    @classmethod
    def read_auto(cls, file_path):
        """自动识别文件类型并读取"""
        ext = os.path.splitext(file_path)[1].lower()

        if ext in ['.txt', '.md', '.markdown']:
            return cls.read_txt(file_path)
        elif ext == '.docx':
            return cls.read_docx(file_path)
        elif ext == '.pdf':
            return cls.read_pdf(file_path)
        else:
            print(f"不支持的文件类型: {ext}")
            return None

    @classmethod
    def get_next_id(cls, jsonl_path):
        """获取下一个可用的 ID"""
        if not os.path.exists(jsonl_path):
            return 1

        try:
            with open(jsonl_path, 'r', encoding='utf-8') as f:
                max_id = 0
                for line in f:
                    if line.strip():
                        data = json.loads(line)
                        if 'id' in data and isinstance(data['id'], int):
                            max_id = max(max_id, data['id'])
                return max_id + 1
        except:
            return 1

    @classmethod
    def save_to_jsonl(cls, file_path, content, jsonl_path='output.jsonl', metadata=None):
        """将读取的内容保存到 JSONL 文件"""
        if content is None:
            print(f"内容为空，跳过保存: {file_path}")
            return None

        # 检查是否已经处理过这个文件
        abs_path = os.path.abspath(file_path)
        if abs_path in cls._processed_files:
            print(f"文件已处理过，跳过: {file_path}")
            return None

        # 生成 ID
        new_id = cls.get_next_id(jsonl_path)

        # 获取文件信息
        file_stat = os.stat(file_path)

        # 准备数据
        data = {
            'id': new_id,
            'description': content,
            'source_file': os.path.basename(file_path),
            'file_path': abs_path,
            'file_type': os.path.splitext(file_path)[1].lower(),
            'file_size': file_stat.st_size,
            'create_time': datetime.fromtimestamp(file_stat.st_ctime).isoformat(),
            'modify_time': datetime.fromtimestamp(file_stat.st_mtime).isoformat(),
            'process_time': datetime.now().isoformat(),
            'content_length': len(content)
        }

        # 添加额外元数据
        if metadata:
            data.update(metadata)

        # 追加写入 JSONL 文件
        try:
            with open(jsonl_path, 'a', encoding='utf-8') as f:
                f.write(json.dumps(data, ensure_ascii=False) + '\n')
            cls._processed_files.add(abs_path)
            return new_id
        except Exception as e:
            print(f"保存到 JSONL 失败: {e}")
            return None

    @classmethod
    def process_and_save(cls, file_path, jsonl_path='output.jsonl', metadata=None):
        """读取文件并自动保存到 JSONL"""
        if not os.path.exists(file_path):
            print(f"文件不存在: {file_path}")
            return None

        print(f"正在处理文件: {file_path}")

        # 读取文件内容
        content = cls.read_auto(file_path)

        if content:
            return cls.save_to_jsonl(file_path, content, jsonl_path, metadata)
        else:
            print(f"读取文件失败: {file_path}")
            return None

    @classmethod
    def read_jsonl(cls, jsonl_path):
        """读取 JSONL 文件的所有记录"""
        records = []
        if os.path.exists(jsonl_path):
            with open(jsonl_path, 'r', encoding='utf-8') as f:
                for line in f:
                    if line.strip():
                        records.append(json.loads(line))
        return records

    @classmethod
    def process_folder(cls, folder_path, jsonl_file='output.jsonl', file_extensions=None):
        """批量处理文件夹中的文件"""
        if file_extensions is None:
            file_extensions = ['.txt', '.md', '.markdown', '.docx', '.pdf']

        processed_count = 0

        for root, dirs, files in os.walk(folder_path):
            for file in files:
                ext = os.path.splitext(file)[1].lower()
                if ext in file_extensions:
                    file_path = os.path.join(root, file)
                    metadata = {
                        'category': '批量导入',
                        'folder': folder_path,
                        'import_time': datetime.now().isoformat()
                    }
                    if cls.process_and_save(file_path, jsonl_file, metadata):
                        processed_count += 1

        print(f"批量处理完成，共处理 {processed_count} 个文件")
        return processed_count

    @classmethod
    def get_by_id(cls, jsonl_path, target_id):
        """根据 ID 获取记录"""
        if not os.path.exists(jsonl_path):
            print(f"文件不存在: {jsonl_path}")
            return None

        with open(jsonl_path, 'r', encoding='utf-8') as f:
            for line in f:
                if line.strip():
                    data = json.loads(line)
                    if data['id'] == target_id:
                        return data
        return None

    @classmethod
    def clear_processed_cache(cls):
        """清空已处理文件缓存"""
        cls._processed_files.clear()
        print("已处理文件缓存已清空")


